UPDATE dc3_mcp_connection
SET revoke_time = #{revokeTime},
operate_time = CURRENT_TIMESTAMP
WHERE id = #{id}
AND tenant_id = #{tenantId}
AND creator_id = #{principalId}
AND deleted = 0

