SELECT id, trace_id, tenant_id, principal_id, principal_type, client_id, connection_id, tool_id, tool_name, permission_code, risk_level, confirm_id, idempotency_key, argument_digest, status, error_code, duration_ms, client_name, client_version, remote_ip, create_time FROM dc3_mcp_audit_log
deleted = 0 AND tenant_id = #{tenantId} AND principal_id = #{principalId} AND tool_id = #{toolId} AND status = #{status} AND risk_level = #{riskLevel}
ORDER BY create_time DESC LIMIT #{limit}

